,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT ''Vizualizare Medici'' AS card_title, ''Gestionare personal medical'' AS card_text, ''fa-user-md'' AS card_icon, ''f?p=&APP_ID.:2:&SESSION.'' AS card_link FROM DUAL',
unistr('UNION ALL SELECT ''Ierarhie Pacien\021Bi'', ''Rela\021Bia pacient-medic'', ''fa-users'', ''f?p=&APP_ID.:4:&SESSION.'' FROM DUAL'),
unistr('UNION ALL SELECT ''Program\0103ri'', ''C\0103utare program\0103ri pacien\021Bi'', ''fa-calendar-alt'', ''f?p=&APP_ID.:6:&SESSION.'' FROM DUAL'),
unistr('UNION ALL SELECT ''Statistici'', ''Raport performan\021B\0103 medici'', ''fa-bar-chart'', ''f?p=&APP_ID.:8:&SESSION.'' FROM DUAL'),
'UNION ALL SELECT ''Vizualizare Programari'', ''Toate programarile din baza de date'', ''fa-calendar'', ''f?p=&APP_ID.:7:&SESSION.'' FROM DUAL',
'UNION ALL SELECT ''Adaugare Programare'', ''Adauga o programare noua'', ''fa-plus'', ''f?p=&APP_ID.:10:&SESSION.'' FROM DUAL',
'UNION ALL SELECT ''Programari pe Specialitate'', ''Filtreaza dupa specialitate'', ''fa-list'', ''f?p=&APP_ID.:11:&SESSION.'' FROM DUAL',
'UNION ALL SELECT ''Statistici Specialitati'', ''Numar medici si pacienti per specialitate'', ''fa-table'', ''f?p=&APP_ID.:13:&SESSION.'' FROM DUAL;'))
,p_lazy_loading=>false
,p_plug_source_type=>'NATIVE_CARDS'
,p_plug_query_num_rows_type=>'SCROLL'
,p_show_total_row_count=>false
