,p_plug_name=>'Statistici Medici'
,p_static_id=>'statistici-medici'
,p_region_template_options=>'#DEFAULT#:t-IRR-region--hideHeader js-addHiddenHeadingRoleDesc'
,p_plug_template=>2102002977963900996
,p_plug_display_sequence=>10
,p_plug_item_display_point=>'ABOVE'
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT ',
'    m.nume AS "Nume Medic",',
'    s.denumire AS "Specialitate",',
'    g.denumire AS "Grad",',
'    COUNT(p.codPro) AS "Numar Programari"',
'FROM cbMedic m',
'JOIN cbSpecialitate s ON m.codSpec = s.codSpec',
'JOIN cbGrad g ON m.codGrad = g.codGrad',
'LEFT JOIN cbProgramare p ON m.medID = p.medID',
'GROUP BY m.nume, s.denumire, g.denumire',
'ORDER BY "Numar Programari" DESC'))
,p_plug_source_type=>'NATIVE_IR'
,p_prn_content_disposition=>'ATTACHMENT'
,p_prn_units=>'INCHES'
,p_prn_paper_size=>'LETTER'
